def max_Product(arr):
    arr.sort()
    max1, max2 = arr[-2], arr[-1]
    min1, min2 = arr[0], arr[1]
    product1 = max1 * max2
    product2 = min1 * min2
    if product1 > product2:
        return (max1, max2)
    else:
        return (min1, min2)

# Test cases
assert max_Product([1,2,3,4,7,0,8,4]) == (7,8)
assert max_Product([0,-1,-2,-4,5,0,-6]) == (-6,-4)
assert max_Product([1,2,3]) == (2,3)

